import React from "react";
import styled from "styled-components";

import { trackGAEvent } from "../../core/services/googleAnalytics";
import {
  feedComponentShape,
  feedCtaButtonShape,
  feedHeaderShape,
} from "./feed-prop-types";

const ButtonColumn = styled.div`
  @media screen and (min-width: 768px) {
    & {
      display: inline-flex;
      justify-content: flex-end;
    }
  }
`;

/**
 *
 * @param {{
 *  defaultProps: import("../../core/types/feed-types").FeedType
 *  header: import("../../core/types/feed-types").FeedHeader
 *  ctaButton: import("../../core/types/feed-types").FeedCtaButton
 * }} props
 * @returns {JSX.Element}
 */
const FeedHeader = ({
  defaultProps,
  header: pHeader,
  ctaButton: pCtaButton,
}) => {
  const header = { ...defaultProps.header, ...pHeader };
  const ctaButton = { ...defaultProps.ctaButton, ...pCtaButton };

  return (
    <div
      className="row justify-content-between align-items-center pb-6"
      data-testid="feed-header"
    >
      <div className="col-sm-12 col-md-9">
        <h2 className={`text-${header.color}`}>{header.text}</h2>
      </div>
      <ButtonColumn className="col-sm-12 col-md-3">
        <a
          className={`btn btn-${ctaButton.color}`}
          href={ctaButton.url}
          onClick={() =>
            trackGAEvent({
              event: "link",
              action: "click",
              name: "onclick",
              type: "internal link",
              text: ctaButton.text,
            })
          }
        >
          {ctaButton.text}
        </a>
      </ButtonColumn>
    </div>
  );
};

FeedHeader.propTypes = {
  defaultProps: feedComponentShape,
  header: feedHeaderShape,
  ctaButton: feedCtaButtonShape,
};

export { FeedHeader };
