import PropTypes from "prop-types";
import React, { useState, useEffect } from "react";

import { accordionCardPropTypes } from "../../core/models/shared-prop-types";
import { trackGAEvent } from "../../core/services/googleAnalytics";
import { AccordionCard } from "./AccordionCard";

const defaultGAEvent = {
  event: "collapse",
  name: "onclick",
  type: "click",
  region: "main content",
};

/**
 * @typedef {import('../../core/types/shared-types').AccordionProps} AccordionProps
 */

/**
 * @param {AccordionProps} props
 * @returns {JSX.Element}
 */
const Accordion = ({ cards, openedCard }) => {
  const [openCard, setOpenCard] = useState(null);

  useEffect(() => {
    setOpenCard(openedCard);
  }, [openedCard]);

  const trackEvent = (cardId, cardTitle) => {
    trackGAEvent({
      ...defaultGAEvent,
      action: openCard === cardId ? "close" : "open",
      text: cardTitle,
    });
  };

  const changeOpenCard = (event, card, cardTitle) => {
    event.preventDefault();
    trackEvent(card, cardTitle);
    setOpenCard((prevState) => (prevState === card ? null : card));
  };

  return (
    <div className="accordion">
      {cards?.map(
        (card, key) =>
          card.content.body &&
          card.content.header && (
            <AccordionCard
              // eslint-disable-next-line react/no-array-index-key
              key={key + 1}
              id={key + 1}
              item={card}
              openCard={openCard}
              onClick={changeOpenCard}
            />
          )
      )}
    </div>
  );
};

Accordion.propTypes = {
  /**
   * Cards to show in the accordion component
   */
  cards: PropTypes.arrayOf(accordionCardPropTypes).isRequired,
  /**
   * Opened card based on rendered card position
   */
  openedCard: PropTypes.number,
};

export { Accordion };
